import React, { Component } from 'react'
import { Carousel,Flex } from 'antd-mobile'
import axios from 'axios';
// 引入样式
import './index.css'
// 引入图片
import nav1 from '../../assets/images/nav-1.png'
import nav2 from '../../assets/images/nav-2.png'
import nav3 from '../../assets/images/nav-3.png'
import nav4 from '../../assets/images/nav-4.png'
const navs = [
  {
    id:1,
    img:nav1,
    title:'整租',
    path:'/home/list'
  },
  {
    id:2,
    img:nav2,
    title:'合租',
    path:'/home/list'
  },
  {
    id:3,
    img:nav3,
    title:'地图找房',
    path:'/home/list'
  },
  {
    id:4,
    img:nav4,
    title:'去出租',
    path:'/home/list'
  },
]

export default class Index extends Component {
  state = {
    // 图片的名称
    swipers:[]
  }
  async getswipers() {
    const res = await axios.get('http://localhost:8080/home/swiper')
    const {body} = res.data
    this.setState({swipers:body})
  }
  componentDidMount() {
    this.getswipers()
  }
  // 渲染轮播图结构
  renderSwipers() {
    return this.state.swipers.map(item => (
      <a
        key={item.id}
        href="#"
        style={{ display: 'inline-block', width: '100%', height: 212 }}
      >
        <img
          src={`http://localhost:8080${item.imgSrc}`}
          alt=""
          style={{ width: '100%', verticalAlign: 'top' }}
        />
      </a>
    ))
  }
  // 
  
  render() {
    return (
      <div className='index'>
        <Carousel
          autoplay={true}
          infinite
        >
          {this.renderSwipers()}
        </Carousel>
        <Flex className='nav'>
          <Flex.Item>
            <img src={nav1} />
            <h2>租房</h2>
          </Flex.Item>
          <Flex.Item>
            <img src={nav2} />
            <h2>租房</h2>
          </Flex.Item>
          <Flex.Item>
            <img src={nav3} />
            <h2>租房</h2>
          </Flex.Item>
          <Flex.Item>
            <img src={nav4} />
            <h2>租房</h2>
          </Flex.Item>
        </Flex>
      </div>
    )
  }
}
